// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Check whether the backend can reach Pixiv
	// (POST /auth/connectivity)
	CheckConnectivity(w http.ResponseWriter, r *http.Request)
	// Log in with a refresh token
	// (POST /auth/login)
	Login(w http.ResponseWriter, r *http.Request)
	// Log out the current session
	// (POST /auth/logout)
	Logout(w http.ResponseWriter, r *http.Request)
	// Complete a browser-driven Pixiv OAuth login
	// (POST /auth/oauth/exchange)
	ExchangeOAuth(w http.ResponseWriter, r *http.Request)
	// Begin a browser-driven Pixiv OAuth (PKCE) login
	// (POST /auth/oauth/start)
	StartOAuth(w http.ResponseWriter, r *http.Request)
	// Get current auth status
	// (GET /auth/status)
	GetAuthStatus(w http.ResponseWriter, r *http.Request)
	// Get the effective config + per-key source layering
	// (GET /config)
	GetConfig(w http.ResponseWriter, r *http.Request)
	// Merge a partial update into the persisted overrides
	// (PATCH /config)
	PatchConfig(w http.ResponseWriter, r *http.Request)
	// Render the download naming templates against a fixed sample work
	// (POST /config/naming/preview)
	PreviewNaming(w http.ResponseWriter, r *http.Request)
	// Drop overrides from the file layer (per key or wholesale)
	// (POST /config/reset)
	ResetConfig(w http.ResponseWriter, r *http.Request)
	// Gracefully restart the process to apply restart-required settings
	// (POST /config/restart)
	RestartConfig(w http.ResponseWriter, r *http.Request)
	// Get the JSON Schema describing all settings
	// (GET /config/schema)
	GetConfigSchema(w http.ResponseWriter, r *http.Request)
	// Bulk-remove terminal download jobs from history
	// (DELETE /downloads)
	ClearDownloads(w http.ResponseWriter, r *http.Request, params ClearDownloadsParams)
	// List download jobs (paginated)
	// (GET /downloads)
	ListDownloads(w http.ResponseWriter, r *http.Request, params ListDownloadsParams)
	// Submit a download job
	// (POST /downloads)
	SubmitDownload(w http.ResponseWriter, r *http.Request)
	// Remove a download job from history
	// (DELETE /downloads/{id})
	RemoveDownload(w http.ResponseWriter, r *http.Request, id DownloadIdPath)
	// Get a download job
	// (GET /downloads/{id})
	GetDownload(w http.ResponseWriter, r *http.Request, id DownloadIdPath)
	// Cancel a running download job
	// (POST /downloads/{id}/cancel)
	CancelDownload(w http.ResponseWriter, r *http.Request, id DownloadIdPath)
	// Subscribe to the event stream
	// (GET /events)
	GetEvents(w http.ResponseWriter, r *http.Request, params GetEventsParams)
	// Check service health
	// (GET /health)
	GetHealth(w http.ResponseWriter, r *http.Request)
	// List illusts from followed users
	// (GET /illusts/following)
	ListFollowingIllusts(w http.ResponseWriter, r *http.Request, params ListFollowingIllustsParams)
	// List ranked illusts
	// (GET /illusts/ranking)
	ListRanking(w http.ResponseWriter, r *http.Request, params ListRankingParams)
	// List recommended illusts
	// (GET /illusts/recommended)
	ListRecommended(w http.ResponseWriter, r *http.Request, params ListRecommendedParams)
	// Get illust detail
	// (GET /illusts/{id})
	GetIllust(w http.ResponseWriter, r *http.Request, id IllustIdPath)
	// Remove an illust bookmark
	// (DELETE /illusts/{id}/bookmark)
	DeleteBookmark(w http.ResponseWriter, r *http.Request, id IllustIdPath)
	// Get current user's bookmark detail for an illust
	// (GET /illusts/{id}/bookmark)
	GetBookmarkDetail(w http.ResponseWriter, r *http.Request, id IllustIdPath)
	// Bookmark an illust
	// (PUT /illusts/{id}/bookmark)
	AddBookmark(w http.ResponseWriter, r *http.Request, id IllustIdPath)
	// Get ugoira metadata
	// (GET /illusts/{id}/ugoira)
	GetUgoiraMetadata(w http.ResponseWriter, r *http.Request, id IllustIdPath)
	// Proxy and cache a Pixiv image
	// (GET /proxy/img)
	ProxyImage(w http.ResponseWriter, r *http.Request, params ProxyImageParams)
	// Search illusts
	// (GET /search/illusts)
	SearchIllusts(w http.ResponseWriter, r *http.Request, params SearchIllustsParams)
	// Search users
	// (GET /search/users)
	SearchUsers(w http.ResponseWriter, r *http.Request, params SearchUsersParams)
	// Get the cached update-check result
	// (GET /system/update)
	GetUpdateStatus(w http.ResponseWriter, r *http.Request)
	// Download, verify, and apply the latest update, then restart
	// (POST /system/update/apply)
	ApplyUpdate(w http.ResponseWriter, r *http.Request)
	// Force an immediate update check against GitHub
	// (POST /system/update/check)
	CheckForUpdate(w http.ResponseWriter, r *http.Request)
	// Get the running binary's version and build info
	// (GET /system/version)
	GetSystemVersion(w http.ResponseWriter, r *http.Request)
	// Get a user's profile detail
	// (GET /users/{id})
	GetUser(w http.ResponseWriter, r *http.Request, id UserIdPath, params GetUserParams)
	// List a user's bookmarks
	// (GET /users/{id}/bookmarks)
	ListUserBookmarks(w http.ResponseWriter, r *http.Request, id UserIdPath, params ListUserBookmarksParams)
	// Unfollow a user
	// (DELETE /users/{id}/follow)
	DeleteFollow(w http.ResponseWriter, r *http.Request, id UserIdPath)
	// Follow a user
	// (PUT /users/{id}/follow)
	AddFollow(w http.ResponseWriter, r *http.Request, id UserIdPath)
	// List users followed by a user
	// (GET /users/{id}/following)
	ListUserFollowing(w http.ResponseWriter, r *http.Request, id UserIdPath, params ListUserFollowingParams)
	// List illusts by a user
	// (GET /users/{id}/illusts)
	ListUserIllusts(w http.ResponseWriter, r *http.Request, id UserIdPath, params ListUserIllustsParams)
}

